#!/bin/bash
[ -n "$1" ] && [ -n "$2" ] && IFS=. read -r i1 i2 i3 i4 <<< "$1" && bin=$(printf "%0.s1" $(seq 1 $2); printf "%0.s0" $(seq 1 $((32 - $2)))) && m1=$((2#${bin:0:8})) && m2=$((2#${bin:8:8})) && m3=$((2#${bin:16:8})) && m4=$((2#${bin:24:8})) && printf "%d.%d.%d.%d - %d.%d.%d.%d" $((i1&m1)) $((i2&m2)) $((i3&m3)) $(( (i4&m4)+1 )) $(( (i1&m1)|(255-m1) )) $(( (i2&m2)|(255-m2) )) $(( (i3&m3)|(255-m3) )) $(( ((i4&m4)|(255-m4))-1 ))
